// Mapeamento nome do time (PT/EN) → código nosso
const NAME_MAP = {
  'mexico':'MEX','méxico':'MEX','south africa':'RSA','africa do sul':'RSA','áfrica do sul':'RSA',
  'south korea':'KOR','coreia do sul':'KOR','korea republic':'KOR','czech republic':'CZE','tchéquia':'CZE','czechia':'CZE',
