  'uruguay':'URU','uruguai':'URU','belgium':'BEL','bélgica':'BEL','egypt':'EGY','egito':'EGY',
  'iran':'IRN','new zealand':'NZL','nova zelândia':'NZL','france':'FRA','frança':'FRA',
  'senegal':'SEN','iraq':'IRQ','iraque':'IRQ','norway':'NOR','noruega':'NOR',
  'argentina':'ARG','algeria':'ALG','argélia':'ALG','austria':'AUT','áustria':'AUT',
  'jordan':'JOR','jordânia':'JOR','portugal':'POR','dr congo':'COD','congo':'COD',
  'england':'ENG','inglaterra':'ENG','croatia':'CRO','croácia':'CRO','ghana':'GHA','gana':'GHA',
  'panama':'PAN','panamá':'PAN','uzbekistan':'UZB','uzbequistão':'UZB','colombia':'COL','colômbia':'COL'
};

function toCode(name) {
  return NAME_MAP[name.toLowerCase().trim()] || null;
}

const toUpdate = [];

// Tenta 1: JSON embutido no HTML (<script> com dados)
const jsonMatches = [];
const scriptMatches = html.matchAll(/\{[^{}]*"(placar|score|gols|gol|home_score|away_score|mandante|visitante)[^{}]*\}/gi);
for (const m of scriptMatches) {
  try { jsonMatches.push(JSON.parse(m[0])); } catch {}
}

// Tenta 2: regex para padrão placar no HTML "TIME 2 x 1 TIME" ou "2-1"
// Padrão: nome_time NUMERO x NUMERO nome_time
const scorePattern = /([A-Za-zÀ-ÿ\s]+?)\s+(\d+)\s*[x×\-]\s*(\d+)\s+([A-Za-zÀ-ÿ\s]+)/gi;
let match;
while ((match = scorePattern.exec(html)) !== null) {
  const homeCode = toCode(match[1].trim());
  const awayCode = toCode(match[4].trim());
  const homeScore = parseInt(match[2]);
  const awayScore = parseInt(match[3]);
  if (!homeCode || !awayCode || isNaN(homeScore) || isNaN(awayScore)) continue;
  const local = MATCHES.find(m => m.home === homeCode && m.away === awayCode);
  if (!local) continue;
  const already = toUpdate.find(u => u.match_id === local.id);
  if (!already) toUpdate.push({ match_id: local.id, home_score: homeScore, away_score: awayScore });
}

// Log para debug (visível no N8N)
console.log('HTML recebido (primeiros 2000 chars):', html.substring(0, 2000));
console.log('Jogos encontrados para atualizar:', JSON.stringify(toUpdate));

if (toUpdate.length === 0) {
  // Retorna o HTML cru para debug caso não encontre nada
  return [{ json: { debug: true, html_preview: html.substring(0, 3000), found: 0 } }];
}

return toUpdate.map(item => ({ json: item }));
